n        //ArrayList<Integer> arr = new ArrayList<>();\n        //arr.add(3);\n        //arr.add(1);\n        //arr.add(9);\n        //arr.add(2);\n        //arr.add(6);\n        //arr.add(8);\n        //arr.add(7);\n        //arr.add(5);\n        //System.out.println(quickSort(arr));\n        //int[] arr = {3, 1, 9, 2, 6, 8, 7, 5};\n        int[] test = new int[8000000];\n        //\u6d4b\u8bd5\u6570\u636e\n        for (int i = 0; i < 8000000; i++) {\n            test[i] = (int) (Math.random() * 800000);\n        }\n        long time = System.currentTimeMillis();\n        quickSort(test);\n        long end = System.currentTimeMillis();\n        long t = ((end - time) / 1000);\n        System.out.println("\u4e00\u5171\u7528\u65f6 " + t + "\u79d2");\n    }\n\n\n    //\u7b80\u6613\u7248\u672c\n    public static ArrayList<Integer> quickSort(ArrayList<Integer> arr) {\n        if (arr == null || arr.size() <= 1) {\n            return arr;\n        }\n        int leader = arr.get(0);\n        //\u5b58\u653e\u5de6\u53f3\u7684\u7ed3\u679c\n        ArrayList<Integer> left = new ArrayList<>();\n        ArrayList<Integer> right = new ArrayList<>();\n        for (int i = 1; i < arr.size(); i++) {\n            if (arr.get(i) <= leader) {\n                left.add(arr.get(i));\n            } else {\n                right.add(arr.get(i));\n            }\n        }\n        //\u9012\u5f52\n        ArrayList<Integer> leftResult = quickSort(left);\n        ArrayList<Integer> rightResult = quickSort(right);\n        //    \u5408\u5e76\n        ArrayList<Integer> result = new ArrayList<>();\n        result.addAll(leftResult);\n        result.add(leader);\n        result.addAll(rightResult);\n        return result;\n    }\n\n\n    //\u6807\u51c6\u7248\u5feb\u901f\u6392\u5e8f\n    public static void quickSort(int[] arr) {\n        quickSort(arr, 0, arr.length - 1);\n    }\n\n    public static void quickSort(int[] arr, int low, int high) {\n        if (low >= high) {\n            return;\n        }\n        //\u5df2\u7ecf\u4ea4\u6362\u8fc7\u4e00\u6b21 \u4e2d\u95f4\u503c\u7684\u4e3a\u6b62\u4e0d\u4f1a\u53d8\u5316\u4e86\n        int partPoint = partition(arr, low, high);\n        //\u9012\u5f52\u5de6\u8fb9\n        quickSort(arr, low, partPoint - 1);\n        //\u9012\u5f52\u53f3\u8fb9\n        quickSort(arr, partPoint + 1, high);\n    }\n\n    //\u8fdb\u884c\u4e00\u6b21\u5de6\u53f3\u6362\u4f4d\n    public static int partition(int[] arr, int low, int high) {\n        int leader = arr[low];\n        while (low < high) {\n            while (low < high && arr[high] >= leader) {\n                //\u4ece\u53f3\u8fb9\u5bfb\u627e\u7b2c\u4e00\u4e2a\u5c0f\u4e8eleader\u7684\u6570\u5b57\n                high--;\n            }\n            //    \u4ea4\u6362\u503c\n            arr[low] = arr[high];\n\n            while (low < high && arr[low] <= leader) {\n                //\u4ece\u5de6\u8fb9\u627e\u5230\u7b2c\u4e00\u4e2a\u5927\u4e8eleader\u7684\u6570\u5b57\n                low++;\n            }\n            arr[high] = arr[low];\n        }\n        arr[low] = leader;\n        return low;\n    }\n}\n\n'})}),"\n",(0,t.jsxs)(r.blockquote,{children:["\n",(0,t.jsx)(r.p,{children:"\u6548\u7387\u7248"}),"\n"]}),"\n",(0,t.jsx)(r.p,{children:"\u601d\u8def\u548c\u6807\u51c6\u7248\u4e00\u81f4"}),"\n",(0,t.jsx)(r.pre,{children:(0,t.jsx)(r.code,{className:"language-Java",children:"//\u901f\u5ea6\u4f18\u5316\u4e4b\u540e\u7684\u5feb\u901f\u6392\u5e8f\npublic static void optimizeQuickSort(int[] arr, int low, int high) {\n    int l = low;\n    int r = high;\n    int pivot = arr[l + r / 2];\n    int temp = 0;\n    while (l < r) {\n        while (arr[l] < pivot) {\n            l += 1;\n        }\n        while (arr[r] > pivot) {\n            r -= 1;\n        }\n        if (l >= r) {\n            break;\n        }\n\n        temp = arr[l];\n        arr[l] = arr[r];\n        arr[r] = temp;\n\n        if (arr[l] == pivot) {\n            r -= 1;\n        }\n        if (arr[r] == pivot) {\n            l += 1;\n        }\n    }\n    //\u9632\u6b62\u6808\u6ea2\u51fa\n    if (l == r) {\n        l += 1;\n        r -= 1;\n    }\n\n    //\u9632\u6b62\u6808\u6ea2\u51fa\uff0c\u5f53low\u6307\u94880 r = 0 \u7684\u65f6\u5019\u5c31\u4e0d\u8bb8\u8981\u6392\u5e8f\u9012\u5f52\u5de6\u8fb9\u4e86\uff0c\n    if (low < r) {\n        quickSort(arr, low, r);\n    }\n    //\u5f53 \u9ad8\u4f4d\u5927\u4e8e \u5de6\u8fb9\u6307\u9488\u7684\u65f6\u5019 \u5c31\u9700\u8981\u5411\u53f3\u8fb9\u9012\u5f52\u4e86\n    if (high > l) {\n        quickSort(arr, l, high);\n    }\n}\n```xxxxxxxxxx //\u901f\u5ea6\u4f18\u5316\u4e4b\u540e\u7684\u5feb\u901f\u6392\u5e8fpublic static void optimizeQuickSort(int[] arr, int low, int high) {    int l = low;    int r = high;    int pivot = arr[l + r / 2];    int temp = 0;    while (l < r) {        while (arr[l] < pivot) {            l += 1;        }        while (arr[r] > pivot) {            r -= 1;        }        if (l >= r) {            break;        }        temp = arr[l];        arr[l] = arr[r];        arr[r] = temp;        if (arr[l] == pivot) {            r -= 1;        }        if (arr[r] == pivot) {            l += 1;        }    }    //\u9632\u6b62\u6808\u6ea2\u51fa    if (l == r) {        l += 1;        r -= 1;    }    //\u9632\u6b62\u6808\u6ea2\u51fa\uff0c\u5f53low\u6307\u94880 r = 0 \u7684\u65f6\u5019\u5c31\u4e0d\u8bb8\u8981\u6392\u5e8f\u9012\u5f52\u5de6\u8fb9\u4e86\uff0c    if (low < r) {        quickSort(arr, low, r);    }    //\u5f53 \u9ad8\u4f4d\u5927\u4e8e \u5de6\u8fb9\u6307\u9488\u7684\u65f6\u5019 \u5c31\u9700\u8981\u5411\u53f3\u8fb9\u9012\u5f52\u4e86    if (high > l) {        quickSort(arr, l, high);    }}Java\n"})})]})}function h(n={}){const{wrapper:r}={...(0,a.R)(),...n.components};return r?(0,t.jsx)(r,{...n,children:(0,t.jsx)(d,{...n})}):d(n)}},28453:(n,r,e)=>{e.d(r,{R:()=>l,x:()=>s});var i=e(96540);const t={},a=i.createContext(t);function l(n){const r=i.useContext(a);return i.useMemo((function(){return"function"==typeof n?n(